var sumOfNumbers = function(l, r, k) {
    const MOD = 1000000007n;
    function power(base, exp, mod) {
        base %= mod;
        let result = 1n;
        while (exp > 0n) {
            if (exp & 1n) result = (result * base) % mod;
            base = (base * base) % mod;
            exp >>= 1n;
        }
        return result;
    }
    let digitSum = 0n;
    for (let d = l; d <= r; d++) digitSum += BigInt(d);
    digitSum %= MOD;
    const count = BigInt(r - l + 1);
    const inv9 = power(9n, MOD - 2n, MOD);
    const repunit = ((power(10n, BigInt(k), MOD) - 1n + MOD) % MOD) * inv9 % MOD;
    const result = digitSum * power(count, BigInt(k - 1), MOD) % MOD * repunit % MOD;
    return Number(result);
};
